import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class XSSSecureCode {
    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter your name: ");
            String userInput = reader.readLine();

            String sanitizedInput = ESAPI.encoder().encodeForHTML(userInput);
            System.out.println("Hello, " + sanitizedInput + "!"); // Escaping user input to prevent XSS

        } catch (IOException e) {
            System.out.println("An error occurred while reading input");
            e.printStackTrace();
        } catch (EncodingException e) {
            System.out.println("An error occurred while encoding input");
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
